+        assert_eq!(decoded.len(), 3);
+
+        // Step 6: Build RVF container
+        let redaction_json = serde_json::to_string(&serde_json::json!({
+            "entries": [], "total_redactions": log.total_redactions
+        })).unwrap();
+        let input = RvfPipelineInput {
