+/// SHAKE-256 hash
+fn sha3_hash(data: &[u8]) -> [u8; 32] {
+    use sha3::{Shake256, digest::{Update, ExtendableOutput, XofReader}};
+    let mut hasher = Shake256::default();
+    hasher.update(data);
+    let mut reader = hasher.finalize_xof();
+    let mut buf = [0u8; 32];
+    reader.read(&mut buf);
+    buf
+}

