+
+    /// Find similar patterns from SONA's learned bank
+    pub fn find_similar(&self, query: &[f32], k: usize) -> Vec<LearnedPattern> {
+        if let Some(ref engine) = self.engine {
+            if let Ok(eng) = engine.lock() {
